        o.PaperDiagnosticsLimited.Enabled=true; o.PaperDiagnosticsLimited.RequireExplicitFlag=true; o.PaperDiagnosticsLimited.AllowedStrategy="SingleMarketBuyBoth"; o.PaperDiagnosticsLimited.MaxOpenPositions=1; o.PaperDiagnosticsLimited.MaxPaperNotionalPerTrade=5m; o.PaperDiagnosticsLimited.MaxPaperTotalExposure=5m; o.PaperDiagnosticsLimited.MaxPaperOpensPerHour=1; o.PaperDiagnosticsLimited.MinEdgeOverride=0.01m; o.PaperPhase1DiscoveryFallback.Enabled=string.Equals(r.AppliedProfile, ReducedDiagnosticsPaperPhase1, StringComparison.OrdinalIgnoreCase); o.PaperPhase1DiscoveryFallback.RequireProfile=ReducedDiagnosticsPaperPhase1; o.PaperPhase1DiscoveryFallback.SnapshotPath="exports/reduced-universe-last-healthy-snapshot.json"; o.PaperPhase1DiscoveryFallback.MaxSnapshotAgeHours=24; o.PaperPhase1DiscoveryFallback.MinMarkets=500; o.PaperPhase1DiscoveryFallback.RequireExplicitFlag=true; o.PaperPhase1DiscoveryFallback.AllowWhenGammaTimeout=true; o.PaperPhase1DiscoveryFallback.DiagnosticsOnly=false; o.PaperPhase1EligibilityLadder.Enabled=string.Equals(r.AppliedProfile, ReducedDiagnosticsPaperPhase1, StringComparison.OrdinalIgnoreCase); o.PaperPhase1EligibilityLadder.ExportEnabled=string.Equals(r.AppliedProfile, ReducedDiagnosticsPaperPhase1, StringComparison.OrdinalIgnoreCase); o.PaperPhase1EligibilityLadder.ExportPath="exports/paper-phase1-near-eligible-latest.json"; o.PaperPhase1EligibilityLadder.MaxItems=250; o.PaperPhase1EligibilityLadder.NearEdgeWindow=0.015m; o.PaperPhase1EligibilityLadder.TrackValidPricedOnly=true; o.PaperPhase1EligibilityLadder.IncludeInvalidTopReasons=true; o.PaperPhase1EligibilityLadder.IncludeMissingPricingSummary=true; o.PaperPhase1EligibilityLadder.IncludeGateBreakdown=true; o.PaperPhase1EligibilityLadder.DiagnosticsOnly=true;
        o.SingleMarketOpportunityAudit.Enabled=true; o.SingleMarketOpportunityAudit.NearMissExportEnabled=true; o.SingleMarketOpportunityAudit.NearMissTopN=50; o.SingleMarketOpportunityAudit.EmitCycleSummary=true; o.SingleMarketArb.AuditBelowMinEdgeEvents=true; o.SingleMarketArb.TopNearMissCount=50; o.SingleMarketArb.LogBatchSummaries=true;
        o.EnableLiveExecution=false; o.EnablePaperTrading=true; o.PaperOnly=true; o.TradingMode.LiveTradingEnabled=false; o.TradingMode.PaperTradingEnabled=true; o.TradingMode.PaperPhase= string.Equals(r.AppliedProfile, ReducedDiagnosticsPaperPhase1, StringComparison.OrdinalIgnoreCase) ? 1 : 2; o.PaperPhaseValidation.Enabled=false; o.PaperSettlementValidation.Enabled=false;
        o.AutoCandidatePricing.Enabled=true; o.AutoCandidatePricing.MaxCandidatesPerCycle=25; o.AutoCandidatePricing.RequireOrderbookStableNow=true; o.AutoCandidatePricing.RequireReducedUniverseOrderbookStableNow=true; o.AutoCandidatePricing.DiagnosticsOnly=true;
