    public static void ApplyCliOverrides(TradingBotOptions o, string[] args)
    {
        var requested=o.RuntimeProfileRequested; var applied=o.RuntimeProfile; var source=o.RuntimeProfileSource; var overrides=o.RuntimeProfileOverrides;
        var cli = new ConfigurationBuilder().AddCommandLine(args).Build();
        cli.GetSection(TradingBotOptions.SectionName).Bind(o);
        o.RuntimeProfileRequested=requested; o.RuntimeProfile=applied; o.RuntimeProfileSource=source; o.RuntimeProfileOverrides=overrides;
        ValidateSafety(o);
    }

    public static void ValidateSafety(TradingBotOptions o)
    {
        if (!string.Equals(o.RuntimeProfile, ReducedDiagnosticsFullStack, StringComparison.OrdinalIgnoreCase) && !string.Equals(o.RuntimeProfile, ReducedDiagnosticsPaperPhase1, StringComparison.OrdinalIgnoreCase)) return;
        var violations = new List<string>();
        if (o.TradingMode.LiveTradingEnabled || o.EnableLiveExecution) violations.Add("LiveTradingEnabledMustBeFalse");
        if (!o.PaperDiagnosticsLimited.Enabled) violations.Add("PaperDiagnosticsLimitedMustBeEnabled");
        if (!string.Equals(o.PaperDiagnosticsLimited.AllowedStrategy,"SingleMarketBuyBoth",StringComparison.OrdinalIgnoreCase)) violations.Add("AllowedStrategyMustBeSingleMarketBuyBoth");
        if (Mode(o,"SingleMarketBuyBoth")!=StrategyMode.PaperEligible) violations.Add("SingleMarketBuyBothMustBePaperEligible");
        if (Mode(o,"VerifiedMultiOutcome")==StrategyMode.PaperEligible) violations.Add("VerifiedMultiOutcomeMustNotBePaperEligible");
        if (Mode(o,"AutoCandidateMultiOutcome")==StrategyMode.PaperEligible) violations.Add("AutoCandidateMultiOutcomeMustNotBePaperEligible");
        if (Mode(o,"ExperimentalMultiOutcome")!=StrategyMode.Disabled) violations.Add("ExperimentalMultiOutcomeMustBeDisabled");
        if (!o.AutoCandidatePricing.DiagnosticsOnly||!o.FocusUniverse.DiagnosticsOnly||!o.EdgeTransition.DiagnosticsOnly||!o.EdgeCompression.DiagnosticsOnly||!o.SpreadMicrostructure.DiagnosticsOnly||!o.DiagnosticsDashboard.DiagnosticsOnly||!o.DiagnosticsDashboardHistory.DiagnosticsOnly) violations.Add("AnalyticsLayersMustBeDiagnosticsOnly");
        if (o.AllowlistRepair.RefreshPreview.AutoApply) violations.Add("AllowlistRefreshAutoApplyMustBeFalse");
        if (violations.Count==0) return; var msg=string.Join("|",violations); Console.WriteLine($"[RUNTIME_PROFILE_SAFETY_VIOLATION] Profile={o.RuntimeProfile} Violations={msg}"); throw new InvalidOperationException($"Runtime profile safety validation failed: {msg}");
    }

    public static string StartupLog(TradingBotOptions o)
    {
        var paper=string.Join("|", o.Strategies.Where(x=>x.Value.Mode==StrategyMode.PaperEligible&&x.Value.Enabled).Select(x=>x.Key));
        var shadow=string.Join("|", o.Strategies.Where(x=>x.Value.Mode==StrategyMode.ShadowPaperEligible&&x.Value.Enabled).Select(x=>x.Key));
        return $"[RUNTIME_PROFILE] RequestedProfile={N(o.RuntimeProfileRequested)} AppliedProfile={N(o.RuntimeProfile)} ProfileSource={o.RuntimeProfileSource} SafetyProfile={N(o.RuntimeProfile)} LiveTradingEnabled={o.TradingMode.LiveTradingEnabled.ToString().ToLowerInvariant()} PaperTradingEnabled={o.TradingMode.PaperTradingEnabled.ToString().ToLowerInvariant()} PaperEligibleStrategies={paper} ShadowStrategies={shadow} DiagnosticsOnlyLayers=AutoCandidatePricing|OpportunityFamilyRanking|FocusUniverse|EdgeTransition|EdgeCompression|SpreadMicrostructure|SignalRLogNoiseControl|DiagnosticsDashboard|DiagnosticsDashboardHistory DiagnosticsDashboard.Enabled={o.DiagnosticsDashboard.Enabled.ToString().ToLowerInvariant()} DiagnosticsDashboard.ExportEnabled={o.DiagnosticsDashboard.ExportEnabled.ToString().ToLowerInvariant()} DiagnosticsDashboard.ExportPath={o.DiagnosticsDashboard.ExportPath} DiagnosticsDashboard.IncludeTopItems={o.DiagnosticsDashboard.IncludeTopItems.ToString().ToLowerInvariant()} DiagnosticsDashboard.TopItemsLimit={o.DiagnosticsDashboard.TopItemsLimit} DiagnosticsDashboard.WriteIntervalSeconds={o.DiagnosticsDashboard.WriteIntervalSeconds} DiagnosticsDashboard.DiagnosticsOnly={o.DiagnosticsDashboard.DiagnosticsOnly.ToString().ToLowerInvariant()} DiagnosticsDashboardHistory.Enabled={o.DiagnosticsDashboardHistory.Enabled.ToString().ToLowerInvariant()} DiagnosticsDashboardHistory.ExportEnabled={o.DiagnosticsDashboardHistory.ExportEnabled.ToString().ToLowerInvariant()} DiagnosticsDashboardHistory.HistoryPath={o.DiagnosticsDashboardHistory.HistoryPath} DiagnosticsDashboardHistory.JsonlPath={o.DiagnosticsDashboardHistory.JsonlPath} DiagnosticsDashboardHistory.CsvPath={o.DiagnosticsDashboardHistory.CsvPath} DiagnosticsDashboardHistory.SampleIntervalSeconds={o.DiagnosticsDashboardHistory.SampleIntervalSeconds} DiagnosticsDashboardHistory.MaxInMemorySamples={o.DiagnosticsDashboardHistory.MaxInMemorySamples} DiagnosticsDashboardHistory.MaxJsonlFileMb={o.DiagnosticsDashboardHistory.MaxJsonlFileMb} DiagnosticsDashboardHistory.CsvEnabled={o.DiagnosticsDashboardHistory.CsvEnabled.ToString().ToLowerInvariant()} DiagnosticsDashboardHistory.JsonlEnabled={o.DiagnosticsDashboardHistory.JsonlEnabled.ToString().ToLowerInvariant()} DiagnosticsDashboardHistory.DiagnosticsOnly={o.DiagnosticsDashboardHistory.DiagnosticsOnly.ToString().ToLowerInvariant()} ProfileOverridesCount={o.RuntimeProfileOverrides.Length} ProfileOverrides=[{string.Join("|",o.RuntimeProfileOverrides)}] SignalRLogNoiseControl.Enabled={o.SignalRLogNoiseControl.Enabled.ToString().ToLowerInvariant()} SignalRLogNoiseControl.SuppressPayloadTrimmed={o.SignalRLogNoiseControl.SuppressPayloadTrimmed.ToString().ToLowerInvariant()} SignalRLogNoiseControl.PayloadTrimmedSummaryIntervalSeconds={o.SignalRLogNoiseControl.PayloadTrimmedSummaryIntervalSeconds} SignalRLogNoiseControl.PayloadTrimmedFirstNPerRun={o.SignalRLogNoiseControl.PayloadTrimmedFirstNPerRun} SignalRLogNoiseControl.ExportCounters={o.SignalRLogNoiseControl.ExportCounters.ToString().ToLowerInvariant()} SignalRLogNoiseControl.DiagnosticsOnly={o.SignalRLogNoiseControl.DiagnosticsOnly.ToString().ToLowerInvariant()}";
    }

    public static void Export(TradingBotOptions o,string processRunId,string root)
    {
        try{var path=Path.Combine(root,"exports/effective-runtime-config-latest.json");Directory.CreateDirectory(Path.GetDirectoryName(path)!);var payload=new{processRunId,generatedAtUtc=DateTime.UtcNow,requestedProfile=o.RuntimeProfileRequested,appliedProfile=o.RuntimeProfile,profileSource=o.RuntimeProfileSource,profileOverrides=o.RuntimeProfileOverrides,safety=new{liveTradingEnabled=o.TradingMode.LiveTradingEnabled||o.EnableLiveExecution,signingAllowed=false,paperTradingEnabled=o.TradingMode.PaperTradingEnabled&&o.EnablePaperTrading,paperDiagnosticsLimitedEnabled=o.PaperDiagnosticsLimited.Enabled,allowedPaperStrategy=o.PaperDiagnosticsLimited.AllowedStrategy,strategyModes=o.Strategies.ToDictionary(x=>x.Key,x=>x.Value.Mode.ToString()),diagnosticsOnlyLayers=new{autoCandidatePricing=o.AutoCandidatePricing.DiagnosticsOnly,opportunityFamilyRanking=o.OpportunityFamilyRanking.DiagnosticsOnly,focusUniverse=o.FocusUniverse.DiagnosticsOnly,edgeTransition=o.EdgeTransition.DiagnosticsOnly,edgeCompression=o.EdgeCompression.DiagnosticsOnly,spreadMicrostructure=o.SpreadMicrostructure.DiagnosticsOnly,signalRLogNoiseControl=o.SignalRLogNoiseControl.DiagnosticsOnly,diagnosticsDashboard=o.DiagnosticsDashboard.DiagnosticsOnly,diagnosticsDashboardHistory=o.DiagnosticsDashboardHistory.DiagnosticsOnly}},config=new{o.MarketDiscovery,o.StrategyOrchestrator,o.Strategies,o.PaperDiagnosticsLimited,o.PaperPhase1DiscoveryFallback,o.PaperPhase1EligibilityLadder,o.SingleMarketOpportunityAudit,o.SingleMarketArb,o.TradingMode,o.PaperPhaseValidation,o.PaperSettlementValidation,o.AutoCandidatePricing,o.OpportunityFamilyRanking,o.FocusUniverse,o.EdgeTransition,o.EdgeCompression,o.SpreadMicrostructure,o.SignalRLogNoiseControl,o.DiagnosticsDashboard,o.DiagnosticsDashboardHistory}};var json=JsonSerializer.Serialize(payload,new JsonSerializerOptions{WriteIndented=true,PropertyNamingPolicy=JsonNamingPolicy.CamelCase});var tmp=path+".tmp";for(var i=0;i<3;i++){try{File.WriteAllText(tmp,json);File.Move(tmp,path,true);break;}catch(IOException) when(i<2){Thread.Sleep(50);}}}catch(Exception ex){Console.WriteLine($"[RUNTIME_PROFILE_EXPORT_WARNING] Error={ex.Message}");}
    }
    private static StrategyMode Mode(TradingBotOptions o,string k)=>o.Strategies.TryGetValue(k,out var v)?v.Mode:StrategyMode.Disabled;
    private static string N(string? s)=>string.IsNullOrWhiteSpace(s)?"None":s!;
    private static string? ReadProfileAlias(string[] args){for(var i=0;i<args.Length;i++){var a=args[i]; if(a.Equals("--profile",StringComparison.OrdinalIgnoreCase)&&i+1<args.Length)return args[i+1]; if(a.StartsWith("--profile=",StringComparison.OrdinalIgnoreCase))return a[10..];}return null;}
    private static IReadOnlyList<string> FindOverrides(string[] args)=>args.Select((a,i)=>a.Equals("--profile",StringComparison.OrdinalIgnoreCase)?"":a).Where(a=>a.StartsWith("--TradingBot:",StringComparison.OrdinalIgnoreCase)&&!a.StartsWith("--TradingBot:RuntimeProfile",StringComparison.OrdinalIgnoreCase)).Select(a=>a[2..].Split('=')[0]).Distinct(StringComparer.OrdinalIgnoreCase).OrderBy(x=>x,StringComparer.OrdinalIgnoreCase).ToArray();
}
